INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('heelevel3-53250add-moex-00262', 'heelevel3-53250add', 'heelevel3-53250add-moex-110-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '16歲的甲，發現鄰居乙家失火，甲雖成功撲滅火源，但於奮勇滅火之際，不慎打破乙家中的水晶 花瓶，並被火灼傷而支出醫藥費。下列關於甲乙間法律關係之敘述，何者正確？', '["甲為限制行為能力人，未經甲之法定代理人承認前，甲乙間不成立無因管理", "甲得請求乙賠償其醫藥費", "雖甲非出於重大過失，乙仍得請求甲賠償其水晶花瓶", "甲得請求乙支付其成功滅火的報酬 32820、33320 33520"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:05+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": "ef3e66e2c719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "335", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00263', 'heelevel3-53250add', 'heelevel3-53250add-moex-110-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '甲僱用無機車駕照之乙為店員，幫其送便當。乙在送便當途中機車超速撞上未戴安全帽的丙，造 成丙頭部嚴重腦震盪及全身大小挫傷。下列敘述，何者錯誤？', '["僱主甲對於丙之損害，原則上需要丙舉證甲有過失，甲始須負擔賠償責任", "雖事故之發生主要起因於乙超速，但丙未戴安全帽，亦屬與有過失", "若乙並無財產可供賠償，經丙向法院聲請，甲有可能因此一人負擔一部或全部之賠償", "甲若對丙賠償損害，事後得對乙行使求償權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:05+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": "ef3e66e2c719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "335", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00264', 'heelevel3-53250add', 'heelevel3-53250add-moex-110-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '下列關於買賣契約瑕疵擔保責任之敘述，何者正確？', '["買受人履行民法第356條之檢查通知義務，為物之瑕疵擔保責任之成立要件之一。惟依民法第 356條規定，於不能即知之瑕疵，不適用之", "出賣人故意不告知瑕疵於買受人者，買受人即使未履行檢查通知義務，亦不妨礙物之瑕疵擔保 責任之成立", "以特約免除或限制出賣人關於物之瑕疵擔保義務者，如出賣人保證無瑕疵者，其特約為無效", "買受人因重大過失，而不知有價值或效用之瑕疵者，出賣人如保證其無瑕疵時，不負擔保之責"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:05+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": "ef3e66e2c719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "335", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00265', 'heelevel3-53250add', 'heelevel3-53250add-moex-110-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '旅店或其他供客人住宿為目的之場所主人，對於客人所攜帶物品之毀損、喪失時，應負下列何種 責任？', '["縱然通常事變，仍應負責", "僅就抽象輕過失負責任", "僅就具體輕過失負責任", "僅就故意或重大過失負責任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:05+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": "ef3e66e2c719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "335", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00266', 'heelevel3-53250add', 'heelevel3-53250add-moex-110-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '甲受乙委託處理事務，應依委任人之指示，並無給付報酬。依民法規定，甲應盡何種注意義務， 否則將負過失責任？', '["一般人之注意義務", "與處理自己事務為同一之注意", "善良管理人之注意", "通常事變之注意"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:05+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": "ef3e66e2c719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "335", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00267', 'heelevel3-53250add', 'heelevel3-53250add-moex-110-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '甲將其所有之鑽戒一只移轉予乙占有，並設定動產質權，以擔保甲對乙所負債務。乙於占有該鑽 戒期間中，向丙詐稱其為該鑽戒之所有人，將該鑽戒出售予善意且無重大過失之丙，且已實際交 付。下列敘述，何者正確？', '["丙自實際由乙受領交付鑽戒時起，成為該鑽戒之所有人，甲不得請求丙返還", "甲自乙將鑽戒交付予丙之時起，二年內得請求丙返還，但須償還丙支出之價金", "甲自乙將鑽戒交付予丙之時起，一年內得請求丙返還，但須償還丙支出之價金", "甲自乙將鑽戒交付予丙之時起，二年內得請求丙返還，且不須償還丙支出之價金"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:05+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": "ef3e66e2c719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "335", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00268', 'heelevel3-53250add', 'heelevel3-53250add-moex-110-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '乙以其所有之A土地供甲設定第一次序之新臺幣（下同）200萬元最高限額抵押權，以擔保甲對 乙基於二者間之加盟契約所生債權。乙復以A土地供丙設定第二次序100萬元最高限額抵押權， 以擔保丙對丁基於金錢借貸契約所生債權。下列敘述，何者正確？', '["無論乙是否同意，甲、丙間得就各自在A土地上之最高限額抵押權之次序為讓與", "丙對丁所生貸與金錢之債權，如係未約定確定期日者，丁得隨時請求確定乙所擔保之債權", "無論丙是否同意，甲乙得於原債權確定前，重新約定變更第一次序最高限額抵押權所擔保債權 之範圍", "原債權確定前，甲將對乙所生原債權之一部分讓與予丙時，丙成為第一次序最高限額抵押權之 共同抵押權人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:05+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": "ef3e66e2c719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "335", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00269', 'heelevel3-53250add', 'heelevel3-53250add-moex-110-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '甲以暴力搶走乙之鑽錶後，以所有之意思，十年間和平、公然、繼續占有乙之鑽錶，下列敘述， 何者正確？', '["乙得請求甲返還鑽錶", "甲取得鑽錶之所有權", "甲未取得鑽錶所有權", "甲乙共有鑽錶所有權 32820、33320 33520"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:05+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": "ef3e66e2c719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "335", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00270', 'heelevel3-53250add', 'heelevel3-53250add-moex-110-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '甲向乙借新臺幣1000萬元，以甲所有之A地為乙設定普通抵押權，嗣後甲以A地為丙設定普通 地上權，丙在A地上建築B屋。債務清償期屆至，甲無力清償債務，乙聲請法院拍賣A地，但 因B屋之存在，故無人應買。下列敘述，何者正確？', '["乙得聲請法院將B屋與A地併付拍賣，但對於B屋之價金，無優先受清償之權", "乙得聲請法院將B屋與A地併付拍賣，且對於B屋之價金，有優先受清償之權", "乙僅得聲請法院拍賣A地，並無聲請將B屋與A地併付拍賣之權", "乙僅得聲請法院拍賣B屋，並無聲請將B屋與A地併付拍賣之權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:05+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": "ef3e66e2c719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "335", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00271', 'heelevel3-53250add', 'heelevel3-53250add-moex-110-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '甲1、甲2、甲3至甲10等10人，經登記為A區分所有建築物之區分所有人。甲1、甲2、甲3 至甲10等10人依法律規定作成以下規約：甲1得使用A區分所有建築物之頂樓。甲1出賣其專 有部分，移轉其占有於乙，登記乙為A區分所有建築物之區分所有人。乙於受讓時就甲1依該規 約所享有權利一事，不知且非可得而知。下列敘述，何者正確？', '["該規約雖未經登記，但因乙就甲1依該規約所享有權利一事，不知且非可得而知，故得使用A 區分所有建築物之頂樓", "乙就甲1依該規約所享有權利一事，不知且非可得而知，故得使用A區分所有建築物之頂樓", "該規約未經登記，乙因此得使用A區分所有建築物之頂樓", "乙得使用A區分所有建築物之頂樓"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:05+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": "ef3e66e2c719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "335", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL)
